# JIT Assembly Inspection
#
# Examines the native code generated by the BEAM JIT compiler
# to verify zero-copy binary matching and efficient branching.

IO.puts(String.duplicate("=", 80))
IO.puts("JIT ASSEMBLY INSPECTION")
IO.puts(String.duplicate("=", 80))

# Define test codec
defmodule JitCodec do
  use GridCodec

  defcodec do
    field(:id, :u64)
    field(:count, :u32)
    field(:flag, :bool)
  end
end

IO.puts("""

This script inspects the JIT-generated native code for GridCodec.

KEY THINGS TO LOOK FOR IN THE OUTPUT:
-------------------------------------
1. ZERO-COPY BINARY MATCHING:
   - Look for 'bs_match' instructions that don't copy data
   - Avoid: mov to stack (indicates register spill)
   - Want: Direct register-to-register operations

2. BRANCH PREDICTION:
   - Look for 'test' + 'jnz/jz' sequences
   - Few branches = good for CPU pipelining
   - Watch for: excessive conditional jumps

3. REGISTER USAGE:
   - x86_64 has 16 general registers
   - Want: Values stay in registers (rax, rbx, rcx, etc.)
   - Avoid: Frequent push/pop (stack spill)

4. INLINED BIFs:
   - :maps.get should be inlined (no 'call' instruction)
   - Binary construction should use SSE/AVX if available

""")

# Method 1: Disassemble to file
IO.puts(String.duplicate("-", 80))
IO.puts("METHOD 1: :erts_debug.df/1 - Dump to file")
IO.puts(String.duplicate("-", 80))

output_dir = "/workspaces/grid_codec/artifacts/jit_dumps"
File.mkdir_p!(output_dir)

# Note: :erts_debug.df dumps to the current directory with a specific name
# We'll try to capture its output
try do
  # This creates a file like 'Elixir.JitCodec.dis' in current directory
  result = :erts_debug.df(JitCodec)
  IO.puts("Disassembly result: #{inspect(result)}")
  IO.puts("Check current directory for .dis file")
rescue
  e ->
    IO.puts("Error: #{inspect(e)}")
    IO.puts("Note: :erts_debug.df may not be available in all builds")
end

# Method 2: Module info
IO.puts("\n" <> String.duplicate("-", 80))
IO.puts("METHOD 2: Module Attributes")
IO.puts(String.duplicate("-", 80))

IO.puts("\nModule: #{inspect(JitCodec)}")
IO.puts("Functions: #{inspect(JitCodec.__info__(:functions))}")

# Method 3: Abstract code analysis
IO.puts("\n" <> String.duplicate("-", 80))
IO.puts("METHOD 3: BEAM Bytecode Analysis")
IO.puts(String.duplicate("-", 80))

{JitCodec, beam_binary} = :code.get_object_code(JitCodec)

case :beam_lib.chunks(beam_binary, [:abstract_code, :attributes]) do
  {:ok, {_, chunks}} ->
    IO.puts("\nBEAM chunks available:")

    for {chunk_name, _data} <- chunks do
      IO.puts("  - #{chunk_name}")
    end

  {:error, _, reason} ->
    IO.puts("Could not read BEAM chunks: #{inspect(reason)}")
end

# Method 4: Disassemble specific functions
IO.puts("\n" <> String.duplicate("-", 80))
IO.puts("METHOD 4: Function Disassembly")
IO.puts(String.duplicate("-", 80))

IO.puts("\nAttempting :erts_debug.disassemble/1...")

try do
  # Get the function reference
  encode_fun = &JitCodec.encode/1

  # Try to disassemble
  result = :erts_debug.disassemble(encode_fun)
  IO.puts("Disassembly: #{inspect(result, limit: :infinity, printable_limit: :infinity)}")
rescue
  e ->
    IO.puts("Error: #{inspect(e)}")
end

# Method 5: Check JIT status
IO.puts("\n" <> String.duplicate("-", 80))
IO.puts("METHOD 5: JIT Status")
IO.puts(String.duplicate("-", 80))

IO.puts("\nSystem info:")
IO.puts("  Emulator flavor: #{:erlang.system_info(:emu_flavor)}")
IO.puts("  Wordsize: #{:erlang.system_info(:wordsize)} bytes")
IO.puts("  SMP support: #{:erlang.system_info(:smp_support)}")
IO.puts("  Thread pool size: #{:erlang.system_info(:thread_pool_size)}")

# Check if JIT perf support is enabled
case :erlang.system_info(:emu_flavor) do
  :jit ->
    IO.puts("  JIT: ENABLED")

  other ->
    IO.puts("  JIT: #{inspect(other)}")
end

# Method 6: Native code info
IO.puts("\n" <> String.duplicate("-", 80))
IO.puts("METHOD 6: Code Server Info")
IO.puts(String.duplicate("-", 80))

code_info = :code.get_mode()
IO.puts("\nCode mode: #{inspect(code_info)}")

# Get loaded module info
mod_info = :code.get_mode()
IO.puts("Module loading mode: #{inspect(mod_info)}")

# Method 7: Process-level code analysis
IO.puts("\n" <> String.duplicate("-", 80))
IO.puts("METHOD 7: Verify Encoding Behavior")
IO.puts(String.duplicate("-", 80))

test_data = %{id: 12345678901234, count: 1000000, flag: true}
binary = JitCodec.encode(test_data)

IO.puts("\nTest encode:")
IO.puts("  Input: #{inspect(test_data)}")
IO.puts("  Output: #{inspect(binary)}")
IO.puts("  Size: #{byte_size(binary)} bytes")

# Verify zero-copy access
id = JitCodec.get(binary, :id)
IO.puts("  get(:id): #{id}")

IO.puts("""

================================================================================
NEXT STEPS FOR DEEPER ANALYSIS
================================================================================

1. RUN WITH PERF JIT SUPPORT:
   ERL_FLAGS="+JPperf true" iex -S mix
   # Then use perf to see actual native instructions

2. USE GDB FOR LIVE INSPECTION:
   gdb -p <PID>
   (gdb) info registers
   (gdb) disassemble process_main

3. CHECK FOR VECTORIZATION:
   Look for SSE/AVX instructions (movdqu, pxor, etc.)
   These indicate the JIT is using SIMD for binary ops

4. FLAME GRAPH:
   Shows which C functions are hot paths
   Look for: erts_garbage_collect, erts_maps_get, process_main

================================================================================
""")
